-- Chain for a slot for a given archetype (nil if none curated).
function GU.ForSlot(arch, slotId)
    local t = arch and GU.List[arch]
    return t and t[slotId] or nil
end

-- Chain for a slot for the CURRENT player (spec override -> archetype).
function GU.ForPlayerSlot(slotId)
    local IS, SG = AIP.ItemScore, AIP.SpecGuides
    local key = SG and SG.KeyFor and SG.KeyFor()
    if key and GU.BySpec[key] and GU.BySpec[key][slotId] then return GU.BySpec[key][slotId] end
    local arch = IS and IS.PlayerArchetype and IS.PlayerArchetype()
    return GU.ForSlot(arch, slotId)
end

local warm = CreateFrame("Frame")
warm:RegisterEvent("PLAYER_LOGIN")
warm:RegisterEvent("PLAYER_ENTERING_WORLD")
warm:SetScript("OnEvent", function()
    if not GetItemInfo then return end
    local function warmT(byslot)
        for _, chain in pairs(byslot) do
            for _, it in ipairs(chain) do if it[2] then GetItemInfo(it[2]) end end
        end
    end
    for _, byslot in pairs(GU.List) do warmT(byslot) end
    for _, byslot in pairs(GU.BySpec) do warmT(byslot) end
end)
